return-response.set-body:
@{
                JArray redirectUris = null;
                try
                {
                    var requestBody = context.Request.Body.As(preserveContent: true);
                    var urisToken = requestBody != null ? requestBody["redirect_uris"] : null;
                    if (urisToken != null && urisToken.Type == JTokenType.Array)
                    {
                        var parsed = (JArray)urisToken;
                        if (parsed.Count > 0)
                        {
                            redirectUris = parsed;
                        }
                    }
                }
                catch
                {
                    redirectUris = null;
                }

                if (redirectUris == null)
                {
                    redirectUris = new JArray();
                    foreach (var redirectUri in "{{McpClaudeRedirectUrisCsv}}".Split(new[] { ';' }, StringSplitOptions.RemoveEmptyEntries))
                    {
                        redirectUris.Add(redirectUri.Trim());
                    }
                }

                return JObject.FromObject(new {
                    client_id = "{{McpClaudeClientId}}",
                    client_id_issued_at = DateTimeOffset.UtcNow.ToUnixTimeSeconds(),
                    redirect_uris = redirectUris,
                    token_endpoint_auth_method = "none",
                    grant_types = new[] { "authorization_code", "refresh_token" },
                    response_types = new[] { "code" },
                    scope = "{{McpScope}} offline_access"
                }).ToString();
            }
